# test_factorial.py

import math
import pytest

from your_module import factorial  # Replace with the actual module name


@pytest.mark.parametrize(
    ("n", "expected"),
    [
        (0, 1),          # edge case
        (1, 1),          # edge case
        (2, 2),
        (3, 6),
        (5, 120),
        (10, 3628800),
    ],
)
def test_factorial_returns_expected_values(n, expected):
    assert factorial(n) == expected


@pytest.mark.parametrize("n", [20, 50])
def test_factorial_matches_math_factorial_for_larger_inputs(n):
    assert factorial(n) == math.factorial(n)


@pytest.mark.parametrize("n", [-1, -2, -10])
def test_factorial_raises_value_error_for_negative_numbers(n):
    with pytest.raises(ValueError, match="n must be non-negative"):
        factorial(n)


@pytest.mark.parametrize(
    "bad_input",
    [
        None,
        "5",
        [5],
        {"n": 5},
        object(),
    ],
)
def test_factorial_raises_type_error_for_unsupported_input_types(bad_input):
    with pytest.raises(TypeError):
        factorial(bad_input)
